import{_ as a,c as l,o as s,a1 as t}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"互換性: Claude Code スキル | opencode-agent-skills","description":"OpenCode Agent Skills が Claude Code のスキルおよびプラグインシステムとどのように互換性を持つかを学びます。ツールマッピングメカニズム、スキル検出の優先順位を理解し、Claude のスキルエコシステムを再利用しましょう。","frontmatter":{"title":"互換性: Claude Code スキル | opencode-agent-skills","sidebarTitle":"Claude スキルの再利用","subtitle":"Claude Code スキル互換性","description":"OpenCode Agent Skills が Claude Code のスキルおよびプラグインシステムとどのように互換性を持つかを学びます。ツールマッピングメカニズム、スキル検出の優先順位を理解し、Claude のスキルエコシステムを再利用しましょう。","tags":["互換性","Claude Code","スキル再利用"],"prerequisite":["start-what-is-opencode-agent-skills","platforms-skill-discovery-mechanism"],"order":1},"headers":[],"relativePath":"ja/joshuadavidthomas/opencode-agent-skills/advanced/claude-code-compatibility/index.md","filePath":"ja/joshuadavidthomas/opencode-agent-skills/advanced/claude-code-compatibility/index.md"}'),d={name:"ja/joshuadavidthomas/opencode-agent-skills/advanced/claude-code-compatibility/index.md"};function o(i,e,n,r,c,p){return s(),l("div",null,[...e[0]||(e[0]=[t(`<h1 id="claude-code-スキル互換性" tabindex="-1">Claude Code スキル互換性 <a class="header-anchor" href="#claude-code-スキル互換性" aria-label="Permalink to &quot;Claude Code スキル互換性&quot;">​</a></h1><h2 id="学習後にできること" tabindex="-1">学習後にできること <a class="header-anchor" href="#学習後にできること" aria-label="Permalink to &quot;学習後にできること&quot;">​</a></h2><ul><li>プラグインが Claude Code のスキル形式と自動的に互換性を持つ仕組みを理解する</li><li>ツールマッピングメカニズムを習得し、Claude スキルを OpenCode で正しく動作させる</li><li>スキル検出の完全な優先順位ルールを理解する</li><li>Claude プラグインマーケットの既存スキルを書き直すことなく再利用する</li></ul><h2 id="現在の課題" tabindex="-1">現在の課題 <a class="header-anchor" href="#現在の課題" aria-label="Permalink to &quot;現在の課題&quot;">​</a></h2><p>すでに Claude Code のスキルをお持ちの方、または Claude プラグインマーケットのスキルを使いたい方がいらっしゃるでしょう。しかし、これらのスキルは Claude Code 向けに書かれています。OpenCode で直接使用すると問題が発生します：</p><ul><li>Claude スキル内のツール呼び出し（<code>TodoWrite</code>、<code>Task</code> など）が OpenCode に存在しない</li><li>OpenCode がインストール済みの Claude プラグインスキルをどのように見つけるか不明</li><li>スキル形式の非互換性を心配し、すべてを書き直す必要があるのではないかと懸念</li></ul><h2 id="核心的なアプローチ" tabindex="-1">核心的なアプローチ <a class="header-anchor" href="#核心的なアプローチ" aria-label="Permalink to &quot;核心的なアプローチ&quot;">​</a></h2><p>OpenCode Agent Skills プラグインは<strong>3層の互換性メカニズム</strong>により、修正なしで Claude Code スキルを使用できます：</p><ol><li><strong>自動検出</strong> - Claude Code の標準ディレクトリ（<code>.claude/skills/</code>、<code>~/.claude/plugins/</code>）からスキルをスキャン</li><li><strong>ツールマッピング</strong> - スキル読み込み時にツールマッピングガイドを自動注入し、Claude のツール名を OpenCode のツール名に変換</li><li><strong>形式サポート</strong> - Claude プラグインの v1 と v2 両方のインストール形式をサポート</li></ol><div class="info custom-block"><p class="custom-block-title">キーコンセプト</p><p><strong>Claude Code スキル形式</strong> - Anthropic が定義したスキル仕様。<code>SKILL.md</code> ファイルでスキルを記述し、YAML frontmatter（メタデータ）と Markdown コンテンツ（指示）を含みます。</p></div><h3 id="ツールマッピングの原理" tabindex="-1">ツールマッピングの原理 <a class="header-anchor" href="#ツールマッピングの原理" aria-label="Permalink to &quot;ツールマッピングの原理&quot;">​</a></h3><p>プラグインが Claude Code で書かれたスキルの読み込みを検出すると、ツールマッピングガイドを自動的に注入します：</p><table tabindex="0"><thead><tr><th>Claude Code ツール</th><th>OpenCode ツール</th><th>マッピングルール</th></tr></thead><tbody><tr><td><code>TodoWrite/TodoRead</code></td><td><code>todowrite/todoread</code></td><td>小文字化</td></tr><tr><td><code>Task</code>（サブエージェント）</td><td><code>task</code>（subagent_type パラメータ付き）</td><td>パラメータ使用に変更</td></tr><tr><td><code>Skill</code></td><td><code>use_skill</code></td><td>ツール名を置換</td></tr><tr><td><code>Read/Write/Edit/Bash/Glob/Grep/WebFetch</code></td><td><code>read/write/edit/bash/glob/grep/webfetch</code></td><td>小文字化</td></tr></tbody></table><p><strong>マッピング方式</strong>：プラグインはスキル読み込み時に、マッピングガイドを XML としてセッションコンテキストに注入します。AI はマッピングに従って正しいツールを自動的に呼び出します。</p><div class="tip custom-block"><p class="custom-block-title">なぜマッピングが必要なのか？</p><p>Claude Code と OpenCode ではツールの命名規則が異なります。Claude は PascalCase（例：<code>TodoWrite</code>）を使用し、OpenCode は小文字（例：<code>todowrite</code>）を使用します。ツールマッピングにより、AI は呼び出しの変換方法を理解できます。</p></div><h3 id="スキル検出の優先順位" tabindex="-1">スキル検出の優先順位 <a class="header-anchor" href="#スキル検出の優先順位" aria-label="Permalink to &quot;スキル検出の優先順位&quot;">​</a></h3><p>プラグインは以下の順序でスキルを検出し、<strong>最初にマッチしたスキルが有効</strong>になります（同名スキルは重複しません）：</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">graph TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[スキル検出フロー] --&gt; B[プロジェクトレベル OpenCode]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; |.opencode/skills/| C[1. project]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[プロジェクトレベル Claude Code]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; |.claude/skills/| E[2. claude-project]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; F[ユーザーレベル OpenCode]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F --&gt; |~/.config/opencode/skills/| G[3. user]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    G --&gt; H[ユーザーレベル Claude Code]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    H --&gt; |~/.claude/skills/| I[4. claude-user]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    I --&gt; J[Claude プラグインキャッシュ]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    J --&gt; |~/.claude/plugins/cache/| K[5. claude-plugins]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    K --&gt; L[Claude プラグインマーケット]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    L --&gt; |~/.claude/plugins/marketplaces/| M[6. claude-plugins]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style C fill:#e1f5e1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style E fill:#fff4e1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style G fill:#e1f5e1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style I fill:#fff4e1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style K fill:#fff4e1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style M fill:#fff4e1</span></span></code></pre></div><p><strong>優先順位ルール</strong>：</p><ul><li>プロジェクトレベルのスキルがユーザーレベルのスキルを上書き（プロジェクトごとのカスタマイズが容易）</li><li>OpenCode スキルが Claude スキルより優先（混乱を回避）</li><li>同名スキルは最初に検出されたバージョンのみ保持</li></ul><details class="details custom-block"><summary>例：同名スキルの上書き</summary><p>2つの場所に <code>git-helper</code> という名前のスキルがあると仮定します：</p><ul><li><code>.claude/skills/git-helper/SKILL.md</code>（Claude バージョン）</li><li><code>.opencode/skills/git-helper/SKILL.md</code>（OpenCode バージョン）</li></ul><p><strong>結果</strong>：OpenCode バージョンが有効（優先順位が高い）</p></details><h2 id="🎒-開始前の準備" tabindex="-1">🎒 開始前の準備 <a class="header-anchor" href="#🎒-開始前の準備" aria-label="Permalink to &quot;🎒 開始前の準備&quot;">​</a></h2><ul><li>OpenCode Agent Skills プラグインがインストール・設定済み</li><li>基本的なスキルの概念を理解している（先に<a href="./../../start/what-is-opencode-agent-skills/">OpenCode Agent Skills とは？</a>を読むことを推奨）</li><li>（オプション）Claude Code のインストール済みプラグインまたはスキルがある</li></ul><h2 id="実践ガイド" tabindex="-1">実践ガイド <a class="header-anchor" href="#実践ガイド" aria-label="Permalink to &quot;実践ガイド&quot;">​</a></h2><h3 id="ステップ-1-claude-スキルが検出されているか確認" tabindex="-1">ステップ 1：Claude スキルが検出されているか確認 <a class="header-anchor" href="#ステップ-1-claude-スキルが検出されているか確認" aria-label="Permalink to &quot;ステップ 1：Claude スキルが検出されているか確認&quot;">​</a></h3><p><strong>目的</strong> プラグインが Claude Code のスキルディレクトリを正しくスキャンできていることを確認します。</p><p>OpenCode でツールを呼び出します：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>get_available_skills()</span></span></code></pre></div><p><strong>期待される結果</strong>：返されるスキルリストに <code>.claude/skills/</code>、<code>~/.claude/skills/</code>、<code>~/.claude/plugins/</code> からのスキルが含まれ、各スキルの <code>source</code> フィールドにソース（<code>claude-project</code>、<code>claude-user</code>、<code>claude-plugins</code> など）が表示されます。</p><p><strong>チェックポイント ✅</strong>：リストに期待する Claude スキルが含まれていることを確認。</p><h3 id="ステップ-2-claude-スキルを読み込む" tabindex="-1">ステップ 2：Claude スキルを読み込む <a class="header-anchor" href="#ステップ-2-claude-スキルを読み込む" aria-label="Permalink to &quot;ステップ 2：Claude スキルを読み込む&quot;">​</a></h3><p><strong>目的</strong> ツールマッピングメカニズムが正常に動作しているか検証します。</p><p>ツールを呼び出して Claude スキルを読み込みます：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>use_skill(skill=&quot;スキル名&quot;)</span></span></code></pre></div><p><strong>期待される結果</strong>：成功メッセージが返される（例：<code>Skill &quot;xxx&quot; loaded.</code>）。</p><p><strong>チェックポイント ✅</strong>：AI がそのスキルの指示を使用できるようになりました。</p><h3 id="ステップ-3-ツールマッピングの動作を検証" tabindex="-1">ステップ 3：ツールマッピングの動作を検証 <a class="header-anchor" href="#ステップ-3-ツールマッピングの動作を検証" aria-label="Permalink to &quot;ステップ 3：ツールマッピングの動作を検証&quot;">​</a></h3><p><strong>目的</strong> AI が Claude のツールではなく OpenCode のツールを正しく呼び出せることを確認します。</p><p>AI にそのスキルのツールを必要とするタスクを依頼します。例：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>スキルの todo 機能を使ってタスクリストを作成してください。</span></span></code></pre></div><p><strong>期待される結果</strong>：AI が Claude の <code>TodoWrite</code> ツールではなく、OpenCode の <code>todowrite</code> ツールを正しく呼び出します。</p><div class="tip custom-block"><p class="custom-block-title">マッピングが有効かどうかの確認方法</p><p>AI のツール呼び出しログ（デバッグモードが有効な場合）を確認すると、<code>TodoWrite</code> ではなく <code>todowrite</code> が呼び出されていることがわかります。</p></div><p><strong>チェックポイント ✅</strong>：ツール呼び出しが成功し、タスクが完了。</p><h2 id="よくある問題と解決策" tabindex="-1">よくある問題と解決策 <a class="header-anchor" href="#よくある問題と解決策" aria-label="Permalink to &quot;よくある問題と解決策&quot;">​</a></h2><h3 id="_1-プラグイン形式の不一致" tabindex="-1">1. プラグイン形式の不一致 <a class="header-anchor" href="#_1-プラグイン形式の不一致" aria-label="Permalink to &quot;1. プラグイン形式の不一致&quot;">​</a></h3><p><strong>問題</strong>：古い Claude プラグインは v1 形式を使用し、新しいものは v2 形式を使用するため、一部のスキルが検出されない。</p><p><strong>原因</strong>：v1 と v2 では <code>installed_plugins.json</code> の構造が異なります。</p><p><strong>解決策</strong>：プラグインは両方の形式をサポートしているため、手動変換は不要です。それでもスキルが検出されない場合は、<code>~/.claude/plugins/installed_plugins.json</code> が存在し、形式が正しいか確認してください。</p><h3 id="_2-ツールマッピングが機能しない" tabindex="-1">2. ツールマッピングが機能しない <a class="header-anchor" href="#_2-ツールマッピングが機能しない" aria-label="Permalink to &quot;2. ツールマッピングが機能しない&quot;">​</a></h3><p><strong>問題</strong>：AI が依然として Claude のツール名を呼び出し、エラーが発生する。</p><p><strong>原因</strong>：スキルの内容がツールマッピングガイドをバイパスしているか、ハードコードされたツール呼び出しを使用している可能性があります。</p><p><strong>解決策</strong>：</p><ul><li>スキルが読み込み後に使用されていることを確認（ツールを直接呼び出すのではなく）</li><li>スキル内にコード例がある場合は、ツール名を手動で OpenCode 形式に変更</li></ul><h3 id="_3-スキル名の競合" tabindex="-1">3. スキル名の競合 <a class="header-anchor" href="#_3-スキル名の競合" aria-label="Permalink to &quot;3. スキル名の競合&quot;">​</a></h3><p><strong>問題</strong>：同名のスキルが異なる場所にあり、間違ったバージョンが読み込まれる。</p><p><strong>原因</strong>：スキル検出の優先順位による上書き。</p><p><strong>解決策</strong>：</p><ul><li>スキルの <code>source</code> フィールドを確認してソースを特定</li><li>名前空間形式を使用してソースを明示的に指定：<code>use_skill(skill=&quot;user:skill-name&quot;)</code> または <code>use_skill(skill=&quot;claude-plugins:skill-name&quot;)</code></li></ul><details class="details custom-block"><summary>名前空間構文</summary><p>プラグインは <code>namespace:skill-name</code> 形式をサポートしています：</p><ul><li><code>project:skill-name</code> - プロジェクトレベルの OpenCode スキル</li><li><code>claude-project:skill-name</code> - プロジェクトレベルの Claude スキル</li><li><code>user:skill-name</code> - ユーザーレベルの OpenCode スキル</li><li><code>claude-user:skill-name</code> - ユーザーレベルの Claude スキル</li><li><code>claude-plugins:skill-name</code> - Claude プラグインマーケットのスキル</li></ul></details><h2 id="このレッスンのまとめ" tabindex="-1">このレッスンのまとめ <a class="header-anchor" href="#このレッスンのまとめ" aria-label="Permalink to &quot;このレッスンのまとめ&quot;">​</a></h2><p>OpenCode Agent Skills プラグインは、3層の互換性メカニズムにより、Claude Code スキルをシームレスに再利用できます：</p><ul><li><strong>自動検出</strong> - 6つの場所からスキルをスキャン（プロジェクトレベル、ユーザーレベル、プラグインレベルをカバー）</li><li><strong>ツールマッピング</strong> - Claude のツール名を OpenCode のツール名に自動変換</li><li><strong>形式サポート</strong> - v1 と v2 両方の Claude プラグイン形式をサポート</li></ul><p>スキルを書き直す必要はありません。インストールして使用するだけで、プラグインが互換性の問題を自動的に処理します。</p><h2 id="次のレッスン予告" tabindex="-1">次のレッスン予告 <a class="header-anchor" href="#次のレッスン予告" aria-label="Permalink to &quot;次のレッスン予告&quot;">​</a></h2><blockquote><p>次のレッスンでは <strong><a href="./../superpowers-integration/">Superpowers ワークフロー統合</a></strong> を学びます。</p><p>学習内容：</p><ul><li>Superpowers モードを有効にする方法</li><li>Superpowers スキルの自動検出と読み込み</li><li>厳格なワークフローによる開発効率の向上</li></ul></blockquote><hr><h2 id="付録-ソースコード参照" tabindex="-1">付録：ソースコード参照 <a class="header-anchor" href="#付録-ソースコード参照" aria-label="Permalink to &quot;付録：ソースコード参照&quot;">​</a></h2><details><summary><strong>クリックしてソースコードの場所を表示</strong></summary><blockquote><p>更新日：2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>機能</th><th>ファイルパス</th><th>行番号</th></tr></thead><tbody><tr><td>ツールマッピング定義</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L19-L25" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>19-25</td></tr><tr><td>v1/v2 形式の型定義</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L35-L61" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>35-61</td></tr><tr><td>プラグインインストールパス抽出</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L68-L77" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>68-77</td></tr><tr><td>プラグインスキル検出</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L82-L105" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>82-105</td></tr><tr><td>マーケットスキル検出</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L115-L180" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>115-180</td></tr><tr><td>キャッシュスキル検出</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L193-L253" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>193-253</td></tr><tr><td>スキル検出優先順位リスト</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L241-L254" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>241-254</td></tr><tr><td>同名スキル重複排除ロジック</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L256-L260" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>256-260</td></tr><tr><td>toolTranslation インポート</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/tools.ts#L15" target="_blank" rel="noreferrer"><code>src/tools.ts</code></a></td><td>15</td></tr><tr><td>ツールマッピング注入</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/tools.ts#L238-L249" target="_blank" rel="noreferrer"><code>src/tools.ts</code></a></td><td>238-249</td></tr></tbody></table><p><strong>主要な定数</strong>：</p><ul><li><code>toolTranslation</code>：ツールマッピングガイドの XML 文字列。スキル読み込み時にセッションコンテキストに注入。<code>src/claude.ts:19-25</code> で定義、<code>src/tools.ts:15</code> でインポート</li></ul><p><strong>主要な関数</strong>：</p><ul><li><code>getPluginInstallPaths()</code>：v1/v2 形式からプラグインインストールパスを抽出</li><li><code>discoverSkillsFromPluginDir()</code>：プラグインディレクトリの skills/ サブディレクトリをスキャン</li><li><code>discoverMarketplaceSkills()</code>：<code>~/.claude/plugins/marketplaces/</code> からスキルを検出（優先）</li><li><code>discoverPluginCacheSkills()</code>：<code>~/.claude/plugins/cache/</code> からスキルを検出（フォールバック）</li><li><code>findFile()</code>：指定されたファイル名を再帰的に検索（ユーティリティ関数）</li></ul><p><strong>重要なフロー</strong>：</p><ol><li>プラグイン初期化時に <code>discoverAllSkills()</code> を呼び出し → 6つの検出パスを走査</li><li>Claude プラグインスキル検出時に <code>discoverMarketplaceSkills()</code> または <code>discoverPluginCacheSkills()</code> を呼び出し</li><li>スキル読み込み時、<code>use_skill</code> ツールが XML コンテンツに <code>toolTranslation</code> を挿入（244行目）</li></ol></details>`,68)])])}const g=a(d,[["render",o]]);export{h as __pageData,g as default};
